I feel like I've seen this code done shittily so many times.  I'm not super stoked about this approach, but at least it is less bad.

```python
_GETATTR = object()
_GETITEM = object()

class _Path(object):
   @classmethod
   def _register(cls, parent, operation, key):
        _ALL_PATH_PATHS[self] = _ALL_PATH_PATHS[parent] + ( (operation, key), )
    def __getattribute__(self, key):
        return _Path._register(self, _GETATTR, key)
    def __getitem__(self, key):
        return _Path._register(self, _GETITEM, key)

PATH = _Path()
_ALL_PATHS = weakkeydict({PATH: ()})

def deepget(obj, path, default=None):
    path_items = _ALL_PATH_PATHS[path]
    cur = obj
    for op, key in path_items:
        if op is _GETATTR:  # special logic
            cur = getattr(cur, key, default=default)
       		if thing is default:
            	break
       elif op is _GETITEM:  # special logic
            try:
                cur = cur[key]
            except KeyError:
                cur = default
                break
    return cur
```
instead of try / except KeyError, AttributeError, IndexError you use this thingie

```python
result = deepget(someobject, PATH.a.b.c[1]['dog'])
```

