}

diskdata sda1 {
    cache_timeout = 30
    disk = "sda1"
    format = " /{free} GB {used_percent}%"
    on_click 1 = "exec thunar /"
}

sysdata mem {
    cache_timeout = 5
    format = "[\?color=mem  RAM: {mem_used_percent}%]"
